import React, { useEffect, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function BrowsePage() {
  const { API } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);

  const search = searchParams.get('search') || '';
  const sort = searchParams.get('sort') || 'popular';

  useEffect(() => {
    setLoading(true);
    axios
      .get(`${API}/movies`, { params: { search, sort, limit: 50 } })
      .then((res) => setMovies(res.data.movies || []))
      .catch(() => setMovies([]))
      .finally(() => setLoading(false));
  }, [API, search, sort]);

  const setSort = (nextSort) => {
    const next = new URLSearchParams(searchParams);
    next.set('sort', nextSort);
    setSearchParams(next);
  };

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      <section className="section" style={{ display: 'flex', justifyContent: 'space-between', gap: '12px', flexWrap: 'wrap' }}>
        <h1 className="section-title" style={{ marginBottom: 0 }}>Browse</h1>
        <div style={{ display: 'flex', gap: '8px' }}>
          {['popular', 'rating', 'year'].map((item) => (
            <button
              key={item}
              className={`genre-pill ${sort === item ? 'active' : ''}`}
              onClick={() => setSort(item)}
            >
              {item}
            </button>
          ))}
        </div>
      </section>

      {loading ? (
        <div>Loading movies...</div>
      ) : (
        <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '14px' }}>
          {movies.map((movie) => (
            <Link key={movie._id} to={`/movie/${movie._id}`} className="movie-card" style={{ height: '280px' }}>
              <img src={movie.thumbnail} alt={movie.title} loading="lazy" />
              <div className="card-overlay">
                <div className="card-title">{movie.title}</div>
              </div>
            </Link>
          ))}
        </section>
      )}
    </main>
  );
}
